const body = $input.first().json.body ?? $input.first().json;

if (!body.page_key || !body.lang || !body.sections) {
  throw new Error('Faltan campos requeridos: page_key, lang, sections');
}

const LANG_NAMES = {
  es: 'Spanish', en: 'English',
  pt: 'Portuguese',
  fr: 'French', de: 'German', it: 'Italian',
  nl: 'Dutch', pl: 'Polish', tr: 'Turkish',
  sv: 'Swedish', cs: 'Czech', ro: 'Romanian',
  id: 'Indonesian', hu: 'Hungarian', da: 'Danish',
  fi: 'Finnish', ca: 'Catalan', no: 'Norwegian',
  sk: 'Slovak', hr: 'Croatian', vi: 'Vietnamese',
  ms: 'Malay', af: 'Afrikaans', eu: 'Basque',
  gl: 'Galician', sw: 'Swahili',
};
const target = LANG_NAMES[body.lang] || body.lang;

const entries = Object.entries(body.sections);
const output = [];

for (const [key, sectionData] of entries) {
  const texts = sectionData.texts;
  if (!Array.isArray(texts)) {
    throw new Error(`Section ${key} must contain a 'texts' array`);
  }
  const n = texts.length;
  const system = `You are a professional localizer, not a word-for-word translator. Localize the provided Spanish texts to ${target}.

Rules (STRICTLY follow ALL of these):
1. Return ONLY a JSON array of localized strings in the EXACT SAME order as input
2. CRITICAL: The input has EXACTLY ${n} items. Your output MUST have EXACTLY ${n} items â€” no more, no less. Do NOT split one item into two, do NOT merge two items into one.
3. Use natural, idiomatic ${target} â€” prefer the standard industry term or common expression over a literal translation when one exists. Examples:
   - "Preguntas frecuentes" â†’ "FAQ" (short label context)
   - "Preguntas Â· lo que siempre consultan" â†’ "FAQ Â· What You Always Ask"
   - "Inicio" â†’ "Home", "Sobre nosotros" â†’ "About Us", "Contacto" â†’ "Contact"
   - "Pliegos" â†’ "Tenders", "Presupuesto" â†’ "Quote"
4. SPLIT PHRASES: HTML often splits a sentence across multiple elements. When consecutive items clearly form a single known phrase, translate each part so the whole reads naturally. Examples:
   - ["Preguntas", "frecuentes."] â†’ ["Frequently Asked", "Questions."] (NOT ["FAQ", "frequently."])
   - ["MÃ¡s de", "15 sistemas"] â†’ ["More than", "15 systems"]
5. Preserve all placeholders, variables, and formatting exactly (e.g., {name}, {{ variable }}, %s)
6. Do NOT translate: brand names (Magoreal), technical terms (Django, Python, OpenAI, GPT, PostgreSQL, Redis, Docker, Nginx, Flutter, WhatsApp, FastAPI, Tailwind, Alpine.js, etc.)
7. COUNT INTEGRITY: The HTML source uses inline <span> tags with color classes to highlight key terms. Each text fragment between tags counts as a separate item. You MUST preserve the EXACT same number of items so these color highlights align correctly. Never merge adjacent items even if they form a phrase.
8. Short UI labels used as standalone headings or nav items MUST use their standard ${target} equivalent
9. Q&A CONTEXT: Items starting with "Â¿" or ending with "?" are questions; the items that follow are their answers. When translating an answer, use the context of its preceding question so terminology and register are consistent between question and answer. Example: if the question asks about "Â¿CuÃ¡nto tarda?", the answer should use the same time-related vocabulary as the translated question.
10. Output NOTHING else: no markdown, no explanation, no code fences, no extra text`;

  output.push({
    json: {
      page_key: body.page_key,
      lang: body.lang,
      section_key: key,
      expected_count: n,
      total_sections: entries.length,
      system,
      user: JSON.stringify(texts),
    }
  });
}

return output;

// Code node v2 corre runOnceForAllItems por defecto.
// Usamos Ã­ndice para emparejar OpenAI responses con su contexto de Build batches.
const openaiItems = $input.all();
const buildItems = $('Build batches').all();

if (openaiItems.length !== buildItems.length) {
  throw new Error(`Mismatch de items: ${openaiItems.length} OpenAI vs ${buildItems.length} Build batches`);
}

const output = [];

for (let i = 0; i < openaiItems.length; i++) {
  const openaiResp = openaiItems[i].json;
  const context = buildItems[i].json;

  const raw = openaiResp.choices?.[0]?.message?.content ?? '';
  if (!raw) {
    throw new Error(`OpenAI no devolvio texto para ${context.section_key}. Respuesta: ` + JSON.stringify(openaiResp).substring(0, 200));
  }

  let cleaned = raw.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/```(?:json)?\n?/g, '').trim();
    if (cleaned.endsWith('```')) {
      cleaned = cleaned.slice(0, -3).trim();
    }
  }

  let translated;
  try {
    translated = JSON.parse(cleaned);
  } catch (e) {
    throw new Error(`JSON invalido para ${context.section_key}. Raw: ` + cleaned.substring(0, 300));
  }

  if (!Array.isArray(translated)) {
    throw new Error(`OpenAI no devolvio un array para ${context.section_key}. Tipo: ` + typeof translated);
  }

  const expected = context.expected_count;

  // Si OpenAI devolvio mas items que la fuente, fusionar consecutivos hasta igualar el conteo
  if (translated.length > expected) {
    const excess = translated.length - expected;
    for (let j = 0; j < excess; j++) {
      // Encontrar el par consecutivo con menor longitud total (el mÃ¡s probable de ser un split)
      let bestIdx = 0;
      let bestLen = Infinity;
      for (let k = 0; k < translated.length - 1; k++) {
        const combined = translated[k].length + translated[k + 1].length;
        if (combined < bestLen) { bestLen = combined; bestIdx = k; }
      }
      translated.splice(bestIdx, 2, (translated[bestIdx] + ' ' + translated[bestIdx + 1]).trim());
    }
  }

  // Si OpenAI devolvio menos, repetir el ultimo texto hasta igualar el conteo
  if (translated.length < expected) {
    const last = translated.length > 0 ? translated[translated.length - 1] : '';
    while (translated.length < expected) translated.push(last);
  }

  output.push({
    json: {
      page_key: context.page_key,
      lang: context.lang,
      section_key: context.section_key,
      translated_texts: translated,
    }
  });
}

return output;

// Recibe arrays de textos traducidos (uno por seccion) y los fusiona.
const allItems = $input.all();
if (!allItems.length) throw new Error('Aggregate: no hay secciones traducidas');

const first = allItems[0].json;
const content = {};

for (const item of allItems) {
  content[item.json.section_key] = item.json.translated_texts;
}

return [{
  json: {
    page_key: first.page_key,
    lang: first.lang,
    content,
    sections_count: Object.keys(content).length,
  }
}];
